import { describe, expect, it, vi } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

vi.mock("next/navigation", () => ({
  useRouter: () => ({ push: vi.fn() }),
}));

import { SearchBar } from "./SearchBar";

describe("<SearchBar />", () => {
  it("renders a search role with the canonical placeholder", () => {
    const html = renderToStaticMarkup(<SearchBar />);
    expect(html).toContain('role="search"');
    expect(html).toContain('type="search"');
    expect(html).toContain("Search medicines, brand, or generic");
  });

  it("hydrates initialQuery into the input value", () => {
    const html = renderToStaticMarkup(<SearchBar initialQuery="para" />);
    expect(html).toContain('value="para"');
  });
});

import { describe, expect, it } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

import { MedicineRow } from "./MedicineRow";

describe("<MedicineRow />", () => {
  it("renders name, distributor, formatted price, and the discount % when MRP > selling price", () => {
    const html = renderToStaticMarkup(
      <MedicineRow
        id="m-paracetamol-500"
        name="Paracetamol 500mg"
        brand="Crocin"
        genericName="Acetaminophen"
        distributorName="MediPlus Distributors"
        mrpPaise={2500}
        sellingPricePaise={2200}
        scheme="10+1 free"
        packSize="10 tablets"
      />,
    );
    expect(html).toContain("Paracetamol 500mg");
    expect(html).toContain("MediPlus Distributors");
    expect(html).toContain("\u20B922.00");
    expect(html).toContain("\u20B925.00");
    expect(html).toContain("% off");
    expect(html).toContain("Scheme: 10+1 free");
    expect(html).toContain("Add to cart");
  });

  it("omits the scheme badge when scheme is null", () => {
    const html = renderToStaticMarkup(
      <MedicineRow
        id="m-amoxicillin-500"
        name="Amoxicillin 500mg cap"
        brand="Mox"
        genericName="Amoxicillin"
        distributorName="MediPlus Distributors"
        mrpPaise={9500}
        sellingPricePaise={8400}
        scheme={null}
        packSize="10 capsules"
      />,
    );
    expect(html).not.toContain("Scheme:");
  });
});
